/**
 * @fileoverview lib/ subdomain policy.
 *
 * `lib/` should not accumulate new files at the top level. Once Phase 4 of
 * the audit close-out (see docs/AUDIT.md) begins, every new or moved file
 * lives under a subdomain folder such as `lib/redis/`, `lib/attendance/`,
 * `lib/auth/`, etc.
 *
 * This rule flags any TypeScript file at the immediate `lib/` level whose
 * basename is *not* on the legacy allow-list. The allow-list lives in
 * `./lib-legacy-whitelist.json` and is regenerated by hand from the
 * current `lib/*.ts` set. To migrate a file into a subdomain folder:
 *
 *   1. Move the file and rewrite the imports.
 *   2. Add `<subdomain>/<basename>` to the JSON allow-list so the moved
 *      file is permitted in its new home.
 *   3. Remove the legacy entry from the JSON allow-list.
 *
 * To add a NEW top-level `lib/` file (rare; only when the work does not
 * belong to any subdomain), append its basename to the JSON allow-list
 * with a comment justifying why the subdomain taxonomy does not fit.
 */

import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const RULES_DIR = __dirname;
const WHITELIST_PATH = path.join(RULES_DIR, "lib-legacy-whitelist.json");

let whitelistCache = null;

function loadWhitelist() {
  if (whitelistCache !== null) return whitelistCache;
  try {
    const raw = fs.readFileSync(WHITELIST_PATH, "utf8");
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) {
      throw new Error("lib-legacy-whitelist.json must be a JSON array of strings");
    }
    whitelistCache = new Set(parsed.map((entry) => String(entry)));
  } catch (err) {
    whitelistCache = new Set();
    console.warn(
      `[eslint] could not load ${WHITELIST_PATH}: ${err.message}. ` +
        "All top-level lib/ files will be reported. Run `npm run lint:rebuild-whitelist` to fix.",
    );
  }
  return whitelistCache;
}

function isTopLevelLibFile(filename) {
  if (typeof filename !== "string" || !filename) return false;
  // Normalize Windows paths to forward slashes.
  const normalized = filename.replace(/\\/g, "/");
  // Must live directly under `lib/` (not under `lib/<sub>/`).
  if (!normalized.endsWith(".ts") && !normalized.endsWith(".tsx")) return false;
  // Find "lib/" segment.
  const libIndex = normalized.lastIndexOf("/lib/");
  if (libIndex === -1) return false;
  const tail = normalized.slice(libIndex + "/lib/".length);
  // Tail must not contain another `/`.
  return tail.length > 0 && !tail.includes("/");
}

function suggestedSubdomain(basename) {
  // Domain-prefix heuristic. Files of the form `<domain>-<feature>.ts(x)`
  // are likely candidates for `lib/<domain>/<feature>.ts(x)`.
  const stripped = basename.replace(/\.(tsx?)$/, "");
  const match = /^([a-z0-9]+)-(.+)$/i.exec(stripped);
  if (!match) return null;
  return { subdomain: match[1].toLowerCase(), feature: match[2] };
}

const MESSAGE_ID = "lib-subdomain-policy";

const rule = {
  meta: {
    type: "suggestion",
    docs: {
      description:
        "Files in lib/ should live in a subdomain folder (lib/<sub>/<name>). " +
        "Top-level lib/ files not on the legacy allow-list are flagged.",
      category: "Stylistic Issues",
      recommended: false,
    },
    schema: [],
    messages: {
      [MESSAGE_ID]:
        "`{{file}}` lives at the top level of `lib/`. Move it into a subdomain folder " +
        "(e.g. `lib/{{suggestedSubdomain}}/{{suggestedFeature}}`) or add it to " +
        "`eslint-rules/lib-legacy-whitelist.json` with a comment justifying why it stays at the top level. " +
        "See `docs/DEVELOPMENT.md` (#lib-subdomain-policy).",
    },
  },
  create(context) {
    return {
      Program(node) {
        const filename = context.filename ?? context.getFilename?.();
        if (!isTopLevelLibFile(filename)) return;
        const basename = path.basename(filename);
        if (loadWhitelist().has(basename)) return;
        const suggestion = suggestedSubdomain(basename);
        context.report({
          node,
          messageId: MESSAGE_ID,
          data: {
            file: basename,
            suggestedSubdomain: suggestion ? suggestion.subdomain : "<choose>",
            suggestedFeature: suggestion ? `${suggestion.feature}.ts` : basename,
          },
        });
      },
    };
  },
};

export default rule;
